THE CLAIM:
{
 "title": "TAM counts PDUs the venture doesn't sell; Germany grows half as fast",
 "narrative": "The model sizes the market as all rack PDUs, but the venture only sells intelligent ones. The intelligent slice is smaller, $2.1B of $2.81B globally, and in Germany it grows just 5.2% a year versus the 9% assumed. Germany carries half the weight, so the venture-relevant base is closer to 70% of the €320M headline.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Venture sells only intelligent PDUs, worth $2.1B of $2.81B.",
   "refs": [
    "profile:Product",
    "digest:tam-global-crosscheck#c11",
    "digest:tam-global-crosscheck#c0"
   ]
  },
  {
   "step": "propagation",
   "text": "Germany's intelligent PDUs grow 5.2%; Eastern Europe buys cheap imports.",
   "refs": [
    "digest:tam-global-crosscheck#c13",
    "digest:tam-global-crosscheck#c14",
    "digest:tam-base#c15"
   ]
  },
  {
   "step": "model-impact",
   "text": "True base is roughly 70% of €320M headline.",
   "refs": [
    "ledger:tamBase",
    "ledger:serviceableFactor"
   ]
  }
 ],
 "falsifier": "A sourced EU split showing intelligent and switched PDUs at 85% or more of CE rack-PDU revenue.",
 "category": "boundary",
 "evidence": [
  {
   "title": "Intelligent PDU",
   "sourceType": "industry-report",
   "publisher": "Global Industry Analysts",
   "date": "2025-10-01",
   "excerpt": "The global market for Intelligent PDU estimated at US$2.1 Billion in the year 2024... Within Europe, Germany is forecast to grow at approximately 5.2% CAGR.",
   "url": "https://www.marketresearch.com/Global-Industry-Analysts-v1039/Intelligent-PDU-42596267/",
   "attached": true
  },
  {
   "title": "Rack Power Distribution Panels Market in Eastern Europe",
   "sourceType": "industry-report",
   "publisher": "IndexBox",
   "date": "2026-06-05",
   "excerpt": "Import dependence remains high at 60–70% of total supply, with finished panels and critical",
   "url": "https://www.indexbox.io/store/eastern-europe-rack-power-distribution-panels-market-analysis-forecast-size-trends-and-insights/",
   "attached": true
  },
  {
   "title": "Rack PDU Market Tracker – 2025",
   "sourceType": "industry-report",
   "publisher": "Omdia",
   "date": "2025-08-27",
   "excerpt": "This is the annual update to the Rack PDU Tracker, including updated forecasts and vendor shares. It uses 2024 as a base year and forecasts to 2030.",
   "url": "https://omdia.tech.informa.com/om129351/rack-pdu-market-tracker--2025",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "tamBase",
  "label": "Central Europe rack-PDU market, all segments/buyers",
  "kind": "estimated",
  "value": 320,
  "unit": "EUR_M",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": null,
  "dimensionValue": null,
  "sensitivityRange": {
   "low": 240,
   "high": 520
  },
  "funnelActive": true,
  "derivation": {
   "method": "Top-down scope-down from the global rack-PDU base",
   "expression": "Global rack-PDU $2.81B (Grand View, 2025) × Europe ≈ 30% [est.; NA = 38% per same source] ≈ $843M ≈ €775M @0.92 (Jul 2026) × CE-7 = 39.8% of Europe colo MW (Statista 2025) ≈ €310M → curated €320M",
   "crossCheck": "Europe DC PDUs+PSUs $2.45B 2024 (BIS/R&M, broader scope) × ~55% PDU share × 39.8% CE ≈ €495M — sets the high end of the band"
  },
  "provenance": {
   "rationale": "No public Europe- or CE-scoped rack-PDU figure exists; both sizing chains are scope-downs from adjacent scopes → wide band, top value-of-information.",
   "promotionPath": "Commission the IndexBox EU Rack PDUs report (country tables) to pin the EU base directly."
  },
  "evidence": [
   {
    "title": "Data Center Rack PDU Market Size | Industry Report, 2033",
    "sourceType": "industry-report",
    "publisher": "Grand View Research",
    "date": "2025",
    "excerpt": "The global data center rack power distribution unit market size was estimated at USD 2.81 billion in 2025 and is projected to reach USD 5.87 billion by 2033... North America held 38.0% revenue share.",
    "attached": true
   },
   {
    "title": "Europe Data Center PDUs and PSUs Market 2025–2035",
    "sourceType": "industry-report",
    "publisher": "Research and Markets / BIS Research",
    "date": "2025",
    "excerpt": "The Europe data center PDUs and PSUs market is projected to reach $20.05 billion by 2035 from $2.45 billion in 2024 — a broader category (PDUs + PSUs) used as the cross-check ceiling.",
    "attached": true
   },
   {
    "title": "IndexBox — Rack PDUs Market in the European Union (country tables)",
    "sourceType": "pending",
    "publisher": "IndexBox",
    "date": null,
    "excerpt": "The directly-scoped EU rack-PDU report exists but its headline figure is paywalled — commissioning it would collapse the ±40% band.",
    "attached": false
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
